Rule.Source:
  import sailpoint.api.Terminator;
  import sailpoint.object.EmailFileAttachment;
  import sailpoint.object.EmailOptions;
  import sailpoint.object.EmailTemplate;
  import sailpoint.object.Filter;
  import sailpoint.object.Identity;
  import sailpoint.object.QueryOptions;
  import sailpoint.object.WorkflowCase;
  import sailpoint.object.WorkItem;
  import sailpoint.tools.Message;
  import sailpoint.tools.Message.Type;
  import sailpoint.tools.Util;
  import java.time.Instant;
  import java.time.temporal.ChronoUnit;
  import java.util.Collections;

  Terminator terminator = new Terminator(context);

  int totalCleanups = 0;
  int totalWorkItemsResolved = 0;
  String joinerWorkflowName = "Ascension-Workflow-Persona-Joiner-Process";

  Instant now = Instant.now(); //Instant of Current Date
  Instant lookBack = now.minus(28, ChronoUnit.DAYS); //Instant of 28 Days [4 Weeks] before Current Date

  long nowMillis = now.toEpochMilli();
  long lookBackMillis = lookBack.toEpochMilli();

  QueryOptions ops = new QueryOptions();

  ops.setCloneResults(true);
  ops.addFilter(Filter.lt("created", new Date(lookBackMillis)));
  ops.addFilter(Filter.like("description","Identity Persona Collision", Filter.MatchMode.START));

  Iterator itr = context.search(WorkItem.class, ops, "id");

  String outFileName = "prunedPersonaCollisionWorkItemReport" + "-" + nowMillis + ".csv";

  ByteArrayOutputStream baos = new ByteArrayOutputStream();
  BufferedWriter bw = new BufferedWriter(new OutputStreamWriter(baos));

  bw.write("IdentityName|DisplayName|Type|FirstName|LastName|MiddleName|EmployeeID|ManagerName|WorkItemDesc");

  try {

    while (itr.hasNext()) {

      //Get WorkItem

      WorkItem workitem = context.getObjectById(WorkItem.class, itr.next()[0]);

      if (workitem != null) {

        totalWorkItemsResolved++;

        //Gather Data from WorkItem

        String description = workitem.getDescription();
        String identityName = workitem.getAttribute("identityName");
        String displayName = workitem.getAttribute("displayName");
        String type = "UnresolvableIdentity";
        String firstName = "UnresolvableIdentity";
        String lastName = "UnresolvableIdentity";
        String middleName = "UnresolvableIdentity";
        String employeeId = "UnresolvableIdentity";
        String managerName = "NoManager";
        Identity manager = null;
        WorkflowCase workflowCase = workitem.getWorkflowCase();
        String underlyingWorkflowName = null;

        //Delete Underlying WorkflowCase (if Underlying Workflow is Joiner)

        if (workflowCase != null) {

          underlyingWorkflowName = workflowCase.getWorkflow().getName();

          if (Util.nullSafeCaseInsensitiveEq(underlyingWorkflowName, joinerWorkflowName)) {

            terminator.deleteObject(workflowCase);

            totalCleanups++;

          }

        }

        //Update Report (if Underlying Workflow is Joiner)

        if (Util.isNotNullOrEmpty(identityName) && Util.nullSafeCaseInsensitiveEq(underlyingWorkflowName, joinerWorkflowName)) {

          Identity identity = context.getObjectByName(Identity.class, identityName);

          if (identity != null) {

            type = identity.getType();
            firstName = identity.getFirstname();
            lastName = identity.getLastname();
            middleName = identity.getAttribute("middleName");
            employeeId = identity.getAttribute("employeeId");
            manager = identity.getManager();

            if (manager != null) {

              managerName = manager.getName();

            }
            
            //Identity was resolvable

            bw.newLine();
            bw.write(identityName + "|" + displayName + "|" + type + "|" + firstName + "|" + lastName + "|" + middleName + "|" + employeeId + "|" + managerName + "|" + description);

          } else {
            
            //Identity was not resolvable

            bw.newLine();
            bw.write(identityName + "|" + displayName + "|" + type + "|" + firstName + "|" + lastName + "|" + middleName + "|" + employeeId + "|" + managerName + "|" + description);

          }

        } else if (Util.nullSafeCaseInsensitiveEq(underlyingWorkflowName, joinerWorkflowName)) {
          
            //identityName is unexpectedly null or empty, but source of WorkItem was Joiner Workflow.

            bw.newLine();
            bw.write(identityName + "|" + displayName + "|" + type + "|" + firstName + "|" + lastName + "|" + middleName + "|" + employeeId + "|" + managerName + "|" + description);

        } 

      }

    }

  } finally { //To account for potential error during WorkItem iteration; always close the BufferedWriter, update TaskResult, and send out a report anyway.

    bw.close();
    Util.flushIterator(itr);

    if (taskResult != null) {

      taskResult.setAttribute("totalCleanups", totalCleanups);
      taskResult.setAttribute("totalWorkItemsResolved", totalWorkItemsResolved);

      if (totalCleanups != totalWorkItemsResolved) {

        taskResult.addMessage(new Message(Message.Type.Warn, "Final totals are not aligned. If no errors were thrown, this is likely due to considered Persona Collision WorkItems that were not produced by the Joiner Workflow.", null));

      }

    }

    //Handle Outgoing Report (Email)

    byte[] bytes = baos.toByteArray();

    EmailFileAttachment file = new EmailFileAttachment("IdentityPersonaCollision-Cleanup-Report-" + nowMillis + ".txt", bytes);

    if (file != null) {

      String subject = "Identity Persona Collision WorkItem Cleanup Report - " + nowMillis;
      String report = "The attached report details Identity Persona Collision WorkItems older than 28 days (four weeks) from the current date, that have been automatically pruned from IdentityIQ. Please note the report is pipe (|) delimited to allow for commas in fields.";

      EmailOptions emailOps = new EmailOptions();
      emailOps.setAttachments(Collections.singletonList(file));
      emailOps.setTo("IdentityCollabSailPointProv@ascension.org");
      emailOps.setVariable("subject", subject);
      emailOps.setVariable("report", report);

      String emailTemplateName = "Ascension-EmailTemplate-ReportOfExpiringADAccts";
      EmailTemplate emailTemplate = context.getObjectByName(EmailTemplate.class, emailTemplateName);

      if (emailTemplate != null) {

        context.sendEmailNotification(emailTemplate, emailOps);

      }

    }

  }
